# -*- coding: utf-8 -*-
import json
from datetime import datetime
from pathlib import Path
from zoneinfo import ZoneInfo

ROOT = Path('/Users/huangxu/Documents/客户管理中心')
run_date = datetime.now(ZoneInfo('Asia/Shanghai')).strftime('%Y-%m-%d')
artifact_path = ROOT / f'outputs/销售渠道运营驾驶舱_{run_date}/artifact.json'
if not artifact_path.is_file():
    raise FileNotFoundError(f'未找到当天主驾驶舱数据产物：{artifact_path}')
artifact = json.loads(artifact_path.read_text())
datasets = artifact['snapshot']['datasets']

def mine(rows, key='销售代表'):
    return [row for row in rows if row.get(key) == '方涛']

orders = mine(datasets['customer_orders'])
alerts = mine(datasets['alert_stage_rows'])
signed = mine(datasets['signed_rows'])
receivables = mine(datasets['receivable_rows'], '销售')
focus = mine(datasets['focus'])
new_accounts = mine(datasets['new_accounts'])
date = datasets['overview'][0]['数据截止日']

data = {'date': date, 'orders': orders, 'alerts': alerts, 'signed': signed, 'receivables': receivables, 'focus': focus, 'newAccounts': new_accounts}
payload = json.dumps(data, ensure_ascii=False, separators=(',', ':')).replace('</', '<\\/')

html = r'''<!doctype html><html lang="zh-CN"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>方涛客户运营中心</title><style>
:root{--blue:#2563eb;--ink:#172033;--muted:#718096;--line:#e3e8f0;--bg:#f4f7fb;--red:#dc2626;--yellow:#d97706;--green:#059669}*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--ink);font:14px -apple-system,BlinkMacSystemFont,"PingFang SC","Microsoft YaHei",sans-serif}button,input,select,textarea{font:inherit}button{cursor:pointer}.shell{max-width:1440px;margin:auto;padding:24px 30px}.top{display:flex;justify-content:space-between;gap:20px;align-items:center}.eyebrow{color:var(--blue);font-size:12px;font-weight:700}.top h1{font-size:28px;margin:5px 0}.top p{margin:0;color:var(--muted)}.brand{padding:12px 16px;border-radius:12px;background:var(--blue);color:#fff;font-size:17px;font-weight:800}.nav{display:flex;gap:5px;margin:22px 0;overflow:auto}.nav button{border:0;background:transparent;color:#64748b;padding:10px 14px;border-radius:9px;white-space:nowrap}.nav button.active{color:var(--ink);background:#fff;box-shadow:0 2px 8px #1e293b12;font-weight:800}.grid{display:grid;gap:14px}.metrics{grid-template-columns:repeat(6,1fr)}.two{grid-template-columns:1.2fr .8fr}.card{background:#fff;border:1px solid var(--line);border-radius:15px;padding:17px;box-shadow:0 2px 5px #1e293b08}.metric span,.task small,.muted{color:var(--muted)}.metric b{display:block;font-size:28px;margin:7px 0 3px}.metric.red b{color:var(--red)}.metric.yellow b{color:var(--yellow)}.metric.green b{color:var(--green)}h2{font-size:17px;margin:0 0 5px}h3{font-size:15px;margin:0}.section-head{display:flex;justify-content:space-between;align-items:center;gap:12px;margin-bottom:14px}.section-head p{margin:0;color:var(--muted);font-size:12px}.task-list{display:grid;gap:9px}.task{display:grid;grid-template-columns:9px 1fr auto;gap:11px;align-items:center;border:1px solid var(--line);padding:11px;border-radius:10px}.task i{width:9px;height:100%;border-radius:8px;background:var(--yellow)}.task.urgent i{background:var(--red)}.task.done{opacity:.55}.task strong{display:block;margin-bottom:3px}.actions{display:flex;gap:6px}.actions button,.primary{border:0;border-radius:7px;padding:7px 9px;background:#edf3ff;color:var(--blue);font-size:12px;font-weight:700}.actions button:last-child,.primary{background:var(--blue);color:#fff}.summary{display:grid;gap:12px}.summary-item{display:flex;justify-content:space-between;padding:10px;background:#f8fafc;border-radius:9px}.summary-item b{font-size:19px}.bar{height:8px;background:#e9eef5;border-radius:99px;overflow:hidden}.bar i{display:block;height:100%;background:var(--green);border-radius:inherit}.filters{display:flex;gap:8px;flex-wrap:wrap}.filters input,.filters select,textarea{border:1px solid var(--line);border-radius:8px;padding:8px 10px;background:#fff;outline:0}.filters input{min-width:220px}.table{overflow:auto;border:1px solid var(--line);border-radius:10px;max-height:580px}table{width:100%;border-collapse:collapse;white-space:nowrap;font-size:12px}th{position:sticky;top:0;background:#f8fafc;color:#64748b;text-align:left;padding:10px}td{padding:10px;border-top:1px solid #eef2f6}tr:hover td{background:#f8fbff}.tag{display:inline-flex;padding:4px 8px;border-radius:99px;font-size:11px;font-weight:700}.tag.red{background:#fee2e2;color:var(--red)}.tag.yellow{background:#fef3c7;color:#a16207}.tag.green{background:#dcfce7;color:var(--green)}.tag.blue{background:#dbeafe;color:var(--blue)}.empty{padding:36px;text-align:center;color:var(--muted)}.form{display:grid;grid-template-columns:1fr 1fr auto;gap:8px;margin-bottom:14px}.form textarea{grid-column:1 / 3;min-height:64px}.hidden{display:none}.note{padding:11px 13px;border-radius:9px;background:#eff6ff;color:#1d4ed8;font-size:12px}.copy{border:1px solid #bcd0ff;background:#f5f8ff;color:var(--blue);border-radius:6px;font-size:11px;padding:4px 7px}.modal{position:fixed;inset:0;z-index:10;display:flex;justify-content:flex-end;background:#17203366;opacity:0;pointer-events:none;transition:opacity .18s}.modal.open{opacity:1;pointer-events:auto}.detail-panel{width:min(440px,100%);height:100%;padding:26px;background:#fff;box-shadow:-12px 0 36px #17203326;transform:translateX(100%);transition:transform .18s}.modal.open .detail-panel{transform:none}.detail-top{display:flex;justify-content:space-between;align-items:flex-start;gap:14px;border-bottom:1px solid var(--line);padding-bottom:18px}.detail-top h2{font-size:20px}.close{border:0;background:#f1f5f9;color:#475569;border-radius:8px;padding:7px 10px;font-weight:700}.detail-card{margin-top:18px;padding:16px;border:1px solid var(--line);border-radius:12px;background:#f8fbff}.detail-card strong{display:block;font-size:17px;margin-top:5px}.detail-card p{color:var(--muted);line-height:1.7;margin:14px 0 0}.detail-actions{display:flex;gap:9px;margin-top:20px}.detail-actions button{border:0;border-radius:8px;padding:10px 13px;background:#edf3ff;color:var(--blue);font-weight:700}.detail-actions button:last-child{background:var(--blue);color:#fff}@media(max-width:1000px){.metrics{grid-template-columns:repeat(3,1fr)}.two{grid-template-columns:1fr}}@media(max-width:640px){.shell{padding:18px 14px}.top{align-items:flex-start;flex-direction:column}.metrics{grid-template-columns:repeat(2,1fr)}.form{grid-template-columns:1fr}.form textarea{grid-column:auto}.filters input{min-width:100%}}
</style></head><body><div class="shell"><header class="top"><div><div class="eyebrow">销售员：方涛 · 数据截止 {{DATE}}</div><h1>方涛客户运营中心</h1><p>助理工作台：发现问题 → 处理问题 → 记录结果 → 完成闭环</p></div><div class="brand">庆方国际 · 客户运营</div></header><nav class="nav" id="nav"></nav><main id="app"></main></div><div class="modal" id="task-detail" onclick="if(event.target===this)closeTask()"></div><script>const D={{DATA}};
const state={tab:'today',q:'',filter:'all',tasks:JSON.parse(localStorage.getItem('fangtao-tasks')||'{}'),records:JSON.parse(localStorage.getItem('fangtao-records')||'[]'),quotes:JSON.parse(localStorage.getItem('fangtao-quotes')||'[]')};
const $=s=>document.querySelector(s), esc=s=>String(s??'—').replace(/[&<>"']/g,x=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[x]));
const num=n=>Number(n||0).toLocaleString('zh-CN',{maximumFractionDigits:0}); const money=n=>'¥'+num(n); const days=r=>Number(String(r['等待/转运时长']||'').match(/[\d.]+/)?.[0]||0);
const save=()=>{localStorage.setItem('fangtao-tasks',JSON.stringify(state.tasks));localStorage.setItem('fangtao-records',JSON.stringify(state.records));localStorage.setItem('fangtao-quotes',JSON.stringify(state.quotes))};
const alertRisk=r=>days(r)>15?'red':days(r)>7?'yellow':'blue';
function customers(){const m=new Map(); D.orders.forEach(r=>{const k=r['客户编码'];if(!m.has(k))m.set(k,{id:k,name:k,orders:0,last:r['拣货日期'],status:'正常'});const x=m.get(k);x.orders++;if(String(r['拣货日期'])>String(x.last))x.last=r['拣货日期']});D.focus.forEach(r=>{if(m.has(r['客户编码'])){let x=m.get(r['客户编码']);x.name=r['客户名称']||x.name;x.status=r['优先级'].startsWith('P0')?'风险客户':r['优先级'].startsWith('P1')?'重点关注':'正常'}});return [...m.values()].sort((a,b)=>b.orders-a.orders)}
function taskList(){let a=D.alerts.filter(r=>r['预警阶段']==='问题件'||days(r)>7).map(r=>({id:'a-'+r['运单号'],kind:'urgent',title:`运单异常：${r['运单号']}`,desc:`${r['客户编码']} · ${r['预警阶段']} · ${r['等待/转运时长']}`}));let r=D.receivables.filter(x=>x['收款状态']==='高风险').map(x=>({id:'r-'+x['客户编码'],kind:'urgent',title:`催收提醒：${x['用户']}`,desc:`未支付 ${money(x['未支付'])} · ${x['结算方式']}`}));let f=D.focus.filter(x=>x['优先级'].startsWith('P0')).map(x=>({id:'f-'+x['客户编码'],kind:'normal',title:`客户跟进：${x['客户名称']||x['客户编码']}`,desc:x['标签']}));return [...a,...r,...f].slice(0,30)}
function tag(v){let c=v==='高风险'||String(v).includes('严重')||String(v).includes('P0')?'red':v==='重点关注'||String(v).includes('延迟')||String(v).includes('P1')?'yellow':v==='正常'||String(v).includes('已签收')?'green':'blue';return `<span class="tag ${c}">${esc(v)}</span>`}
function table(cols,rows){return rows.length?`<div class="table"><table><thead><tr>${cols.map(c=>`<th>${c[1]}</th>`).join('')}</tr></thead><tbody>${rows.map(r=>`<tr>${cols.map(c=>`<td>${c[0]==='运单号'?`<strong>${esc(r[c[0]])}</strong>`:esc(r[c[0]])}</td>`).join('')}</tr>`).join('')}</tbody></table></div>`:'<div class="empty">没有符合条件的记录</div>'}
function today(){let tasks=taskList(),done=tasks.filter(t=>state.tasks[t.id]==='done').length,alert=D.alerts.filter(r=>r['预警阶段']==='问题件'||days(r)>7),due=D.receivables.filter(r=>r['收款状态']==='高风险');return `<div class="grid metrics">${[['今日待处理',tasks.length,'red'],['异常运单',alert.length,'red'],['待签收',D.alerts.length,'yellow'],['待报价',state.quotes.filter(x=>x.status==='待报价').length,'yellow'],['待收款',due.length,'yellow'],['待跟进客户',D.focus.length,'blue']].map(x=>`<section class="card metric ${x[2]}"><span>${x[0]}</span><b>${x[1]}</b><small>方涛负责范围</small></section>`).join('')}</div><div class="grid two" style="margin-top:16px"><section class="card"><div class="section-head"><div><h2>今日必须处理</h2><p>按异常、应收与客户风险优先级排序</p></div><span class="tag red">${tasks.length} 项待办</span></div><div class="task-list">${tasks.slice(0,10).map(t=>`<div class="task ${t.kind} ${state.tasks[t.id]==='done'?'done':''}"><i></i><div><strong>${esc(t.title)}</strong><small>${esc(t.desc)}</small></div><div class="actions"><button onclick="showTask('${t.id}')">详情</button><button onclick="setTask('${t.id}','processing')">处理中</button><button onclick="setTask('${t.id}','done')">完成</button></div></div>`).join('')}</div></section><aside class="card summary"><div><h2>今日完成情况</h2><p class="muted">完成事项会保存在此浏览器</p></div><div class="summary-item"><span>今日任务</span><b>${tasks.length}</b></div><div class="summary-item"><span>已完成</span><b>${done}</b></div><div><div style="display:flex;justify-content:space-between"><span>完成率</span><strong>${tasks.length?Math.round(done/tasks.length*100):0}%</strong></div><div class="bar"><i style="width:${tasks.length?done/tasks.length*100:0}%"></i></div></div><div class="note">已纳入：物流异常、重点客户与高风险应收。报价和沟通记录可在对应页面录入。</div></aside></div>`}
function customerPage(){let rows=customers().filter(x=>!state.q||JSON.stringify(x).toLowerCase().includes(state.q.toLowerCase()));return `<section class="card"><div class="section-head"><div><h2>我的客户</h2><p>仅显示方涛负责的客户；最近联系时间来自本工作台录入记录</p></div><div class="filters"><input placeholder="搜索客户" value="${esc(state.q)}" oninput="state.q=this.value;render()"></div></div>${table([['name','客户'],['status','客户状态'],['orders','近三月运单'],['last','最近下单'],['contact','最近联系']],rows.map(x=>({...x,contact:(state.records.find(r=>r.customer===x.id)||{}).time||'暂无记录'})))}</section>`}
function shipmentPage(){let all=D.orders.filter(r=>!state.q||JSON.stringify(r).toLowerCase().includes(state.q.toLowerCase()));let view=state.filter==='overdue'?D.alerts.filter(r=>days(r)>3):state.filter==='alerts'?D.alerts.filter(r=>days(r)>7):all;return `<section class="card"><div class="section-head"><div><h2>我的运单</h2><p>运输、签收与异常由当天运单报表生成</p></div><div class="filters"><select onchange="state.filter=this.value;render()"><option value="all">全部运单</option><option value="overdue">超时未签收</option><option value="alerts">异常运单</option></select><input placeholder="搜索运单号/客户/服务" value="${esc(state.q)}" oninput="state.q=this.value;render()"></div></div>${table([['运单号','运单号'],['客户编码','客户'],['服务','运输渠道'],['状态','当前状态'],['拣货日期','拣货时间']],view.slice(0,500))}</section>`}
function alertPage(){let rows=D.alerts.filter(r=>!state.q||JSON.stringify(r).toLowerCase().includes(state.q.toLowerCase()));return `<section class="card"><div class="section-head"><div><h2>预警中心</h2><p>助理日常提醒：运单停滞、签收关注与应收影响</p></div><button class="copy" onclick="copyNos()">复制当前运单号</button></div><div class="grid metrics" style="margin-bottom:14px">${[['超72小时未签收',rows.filter(r=>days(r)>3).length,'yellow'],['清关延迟',rows.filter(r=>days(r)>7&&days(r)<=15).length,'yellow'],['严重滞后',rows.filter(r=>days(r)>15).length,'red'],['正常转运',rows.filter(r=>days(r)<=3).length,'green'],['待处理应收',D.receivables.filter(r=>r['收款状态']==='高风险').length,'red'],['异常恢复',0,'green']].map(x=>`<div class="card metric ${x[2]}"><span>${x[0]}</span><b>${x[1]}</b></div>`).join('')}</div><div class="filters" style="margin-bottom:12px"><input placeholder="搜索运单号/客户/服务" value="${esc(state.q)}" oninput="state.q=this.value;render()"></div>${table([['运单号','运单号'],['客户编码','客户'],['渠道类型','渠道'],['状态','当前状态'],['预警阶段','异常原因'],['等待/转运时长','异常时间'],['最后路由','最后路由']],rows.slice(0,500))}</section>`}
function quotes(){return `<section class="card"><div class="section-head"><div><h2>报价跟进</h2><p>源报表没有报价明细；在此录入方涛客户的报价待办</p></div></div><form class="form" onsubmit="addQuote(event)"><input name="customer" placeholder="客户编码或名称" required><select name="status"><option>待报价</option><option>已报价</option><option>等待客户回复</option><option>成交</option></select><button class="primary">新增报价</button><textarea name="note" placeholder="报价内容、客户需求或下一步计划"></textarea></form>${table([['customer','客户'],['status','状态'],['note','报价/下一步'],['time','创建时间']],state.quotes)}</section>`}
function receivable(){let rows=D.receivables.filter(r=>!state.q||JSON.stringify(r).toLowerCase().includes(state.q.toLowerCase()));return `<section class="card"><div class="section-head"><div><h2>应收跟进</h2><p>仅提醒助理需要联系的方涛客户；数据来自当天应收报表</p></div><div class="filters"><input placeholder="搜索客户" value="${esc(state.q)}" oninput="state.q=this.value;render()"></div></div>${table([['用户','客户'],['结算方式','结算方式'],['未支付','待收款'],['收款状态','提醒级别'],['销售','销售']],rows.map(r=>({...r,未支付:money(r['未支付'])})))}</section>`}
function records(){return `<section class="card"><div class="section-head"><div><h2>跟进记录</h2><p>记录客户联系、反馈与下一步计划；保存在当前浏览器</p></div></div><form class="form" onsubmit="addRecord(event)"><input name="customer" placeholder="客户编码或名称" required><input name="plan" placeholder="下一步计划" required><button class="primary">保存记录</button><textarea name="content" placeholder="联系内容与客户反馈" required></textarea></form>${table([['customer','客户'],['time','联系时间'],['content','跟进内容'],['plan','下一步计划']],state.records)}</section>`}
function render(){let page={today,customers:customerPage,shipments:shipmentPage,alerts:alertPage,quotes,receivables:receivable,records}[state.tab]();$('#nav').innerHTML=[['today','今日工作'],['customers','我的客户'],['shipments','我的运单'],['alerts','预警中心'],['quotes','报价跟进'],['receivables','应收跟进'],['records','跟进记录']].map(x=>`<button class="${state.tab===x[0]?'active':''}" onclick="state.tab='${x[0]}';state.q='';state.filter='all';render()">${x[1]}</button>`).join('');$('#app').innerHTML=page}
function setTask(id,v){state.tasks[id]=v;save();closeTask();render()}function showTask(id){let t=taskList().find(x=>x.id===id),status=state.tasks[id]==='done'?'已完成':state.tasks[id]==='processing'?'处理中':'待处理';$('#task-detail').innerHTML=`<aside class="detail-panel" role="dialog" aria-modal="true" aria-label="任务详情"><div class="detail-top"><div><span class="tag ${t.kind==='urgent'?'red':'yellow'}">${status}</span><h2>任务详情</h2></div><button class="close" onclick="closeTask()">关闭</button></div><div class="detail-card"><small>需跟进事项</small><strong>${esc(t.title)}</strong><p>${esc(t.desc)}</p></div><div class="detail-actions"><button onclick="setTask('${t.id}','processing')">标记处理中</button><button onclick="setTask('${t.id}','done')">完成任务</button></div></aside>`;$('#task-detail').classList.add('open')}function closeTask(){$('#task-detail').classList.remove('open')}function copyNos(){let rows=D.alerts.filter(r=>!state.q||JSON.stringify(r).toLowerCase().includes(state.q.toLowerCase()));navigator.clipboard.writeText(rows.map(r=>r['运单号']).join('\n')).then(()=>alert('已复制 '+rows.length+' 个运单号'))}function addQuote(e){e.preventDefault();let f=new FormData(e.target);state.quotes.unshift({customer:f.get('customer'),status:f.get('status'),note:f.get('note'),time:new Date().toLocaleString('zh-CN')});save();render()}function addRecord(e){e.preventDefault();let f=new FormData(e.target);state.records.unshift({customer:f.get('customer'),content:f.get('content'),plan:f.get('plan'),time:new Date().toLocaleString('zh-CN')});save();render()}render();</script></body></html>'''.replace('{{DATE}}', date).replace('{{DATA}}', payload)

enhanced_alert_ui = r'''<style>
.alert-workbench{display:grid;gap:16px}.alert-toolbar{display:flex;justify-content:space-between;align-items:center;gap:14px;padding:10px 12px;border:1px solid var(--line);border-radius:14px;background:#fff}.view-switch,.mode-switch{display:flex;align-items:center;gap:6px}.view-switch{padding:4px;background:#eef2f7;border-radius:10px}.view-switch button,.mode-switch button{border:0;background:transparent;border-radius:8px;padding:8px 12px;color:#64748b;font-weight:700}.view-switch button.active{background:#fff;color:var(--ink);box-shadow:0 1px 5px #17203318}.mode-switch span{color:#94a3b8;font-size:12px;margin-right:4px}.mode-switch button.active{background:#eaf1ff;color:var(--blue);box-shadow:inset 0 0 0 1px #bfd3ff}.stage-kpis{display:grid;grid-template-columns:repeat(6,minmax(0,1fr));gap:12px}.stage-card{border:1px solid var(--line);border-radius:15px;padding:16px 12px;background:#fff;text-align:center;transition:.16s;min-height:118px}.stage-card:hover,.stage-card.active{transform:translateY(-2px);box-shadow:0 8px 20px #17203314;border-color:currentColor}.stage-card span{display:block;color:#718096;font-size:12px;min-height:32px}.stage-card strong{display:block;font-size:29px;line-height:1;margin:8px 0;color:inherit}.stage-card small{color:#94a3b8;font-size:11px}.stage-card.blue{color:var(--blue)}.stage-card.green{color:var(--green)}.stage-card.yellow{color:var(--yellow)}.stage-card.red{color:var(--red)}.alert-table-card{padding:0;overflow:hidden}.alert-table-head{display:flex;justify-content:space-between;gap:14px;align-items:center;padding:18px 18px 12px}.alert-table-head h2{font-size:18px}.alert-table-head p{margin:4px 0 0;color:var(--muted)}.alert-table-head .filters{justify-content:flex-end}.alert-table-card .table{border:0;border-radius:0;max-height:620px}.alert-table-card th{padding:13px 12px;background:#f7f9fc}.alert-table-card td{padding:12px}.alert-table-card tr.red td{background:#fff4f4}.alert-table-card tr.yellow td{background:#fffaf1}.alert-table-card tr.blue td{background:#f5f8ff}.route{max-width:280px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.stage-label{display:inline-flex;padding:5px 8px;border-radius:99px;font-weight:700;font-size:11px}.stage-label.red{color:var(--red);background:#fee2e2}.stage-label.yellow{color:#b45309;background:#fef3c7}.stage-label.blue{color:var(--blue);background:#dbeafe}.stage-label.green{color:var(--green);background:#dcfce7}.copy-status{margin:0 18px 12px;color:var(--green);font-size:12px;font-weight:700}@media(max-width:1000px){.stage-kpis{grid-template-columns:repeat(3,1fr)}.alert-toolbar{align-items:flex-start;flex-direction:column}}@media(max-width:640px){.stage-kpis{grid-template-columns:repeat(2,1fr)}.mode-switch{flex-wrap:wrap}.alert-table-head{align-items:flex-start;flex-direction:column}.alert-table-head .filters{justify-content:flex-start;width:100%}}
</style><script>
state.alertView ||= 'monitor';state.alertStage ||= '全部';state.alertMode ||= '全部';
const alertTone2=s=>String(s).includes('严重')||String(s).includes('问题')?'red':String(s).includes('延迟')||s==='待出货'?'yellow':String(s).includes('正常')?'green':'blue';
const monitorRows=()=>D.alerts.filter(r=>(!state.alertRiskOnly||days(r)>7)&&(state.alertMode==='全部'||r['渠道类型']===state.alertMode)&&(state.alertStage==='全部'||r['预警类型']===state.alertStage)&&(!state.q||JSON.stringify(r).toLowerCase().includes(state.q.toLowerCase()))).sort((a,b)=>days(b)-days(a));
alertPage=function(){let stages=['出仓延迟','头程延迟','清关延迟','尾程延迟','严重滞后'];let rows=monitorRows(),signed=D.signed.filter(r=>(state.alertMode==='全部'||r['渠道类型']===state.alertMode)&&(!state.q||JSON.stringify(r).toLowerCase().includes(state.q.toLowerCase())));let viewing=state.alertView==='signed';let tableRows=viewing?signed:rows;let cols=viewing?[['运单号','运单号'],['客户编码','客户'],['渠道类型','渠道'],['服务','服务'],['签收日期','签收时间'],['签收依据','签收依据']]:[['运单号','运单号'],['客户编码','客户'],['用户等级','等级'],['渠道类型','渠道'],['服务','服务'],['预警类型','预警阶段'],['等待/转运时长','路由停滞 / 等待'],['最后路由时间明细','最后路由时间'],['未支付应收','未支付应收'],['最后路由','最后路由']];return `<div class="alert-workbench"><div class="page-title"><div><h2>预警中心</h2><p>未签收运单按最后路由更新时间识别停滞；仅展示方涛负责范围</p></div><span class="tag ${viewing?'green':'red'}">${tableRows.length} 条${viewing?'签收':'监控'}记录</span></div><div class="alert-toolbar"><div class="view-switch"><button class="${!viewing?'active':''}" onclick="state.alertView='monitor';render()">预警监控</button><button class="${viewing?'active':''}" onclick="state.alertView='signed';render()">正常签收</button></div><div class="mode-switch"><span>运输方式</span>${['全部','空运','海运','其他'].map(x=>`<button class="${state.alertMode===x?'active':''}" onclick="state.alertMode='${x}';render()">${x}</button>`).join('')}</div></div>${!viewing?`<div class="stage-kpis">${stages.map(s=>{let count=D.alerts.filter(r=>(state.alertMode==='全部'||r['渠道类型']===state.alertMode)&&r['预警类型']===s).length,customers=new Set(D.alerts.filter(r=>(state.alertMode==='全部'||r['渠道类型']===state.alertMode)&&r['预警类型']===s).map(r=>r['客户编码'])).size,tone=alertTone2(s);return `<button class="stage-card ${tone} ${state.alertStage===s?'active':''}" onclick="state.alertStage=state.alertStage==='${s}'?'全部':'${s}';render()"><span>${s}</span><strong>${count}</strong><small>${customers} 家客户</small></button>`}).join('')}</div>`:''}<section class="card alert-table-card"><div class="alert-table-head"><div><h2>${viewing?'正常签收明细':'异常运单监控列表'}</h2><p>${viewing?'用于建立渠道正常时效基准':'按最后路由停滞时长降序排列'}</p></div><div class="filters"><input value="${esc(state.q)}" oninput="state.q=this.value;render()" placeholder="搜索运单号/客户/服务">${!viewing?'<button class="copy" onclick="copyNos()">复制当前运单号</button>':''}</div></div>${state.copyMessage&&!viewing?`<p class="copy-status">${esc(state.copyMessage)}</p>`:''}<div class="table"><table><thead><tr>${cols.map(c=>`<th>${c[1]}</th>`).join('')}</tr></thead><tbody>${tableRows.slice(0,500).map(r=>`<tr class="${viewing?'':alertTone2(r['预警类型'])}">${cols.map(c=>{let v=r[c[0]];if(c[0]==='运单号')return `<td><strong>${esc(v)}</strong></td>`;if(c[0]==='预警类型')return `<td><span class="stage-label ${alertTone2(v)}">${esc(v)}</span></td>`;if(c[0]==='渠道类型')return `<td>${tag(v)}</td>`;if(c[0]==='未支付应收')return `<td>${money(v)}</td>`;if(c[0]==='最后路由')return `<td class="route" title="${esc(v)}">${esc(v)}</td>`;return `<td>${esc(v)}</td>`}).join('')}</tr>`).join('')}</tbody></table></div></section></div>`};
copyNos=function(){let rows=monitorRows();navigator.clipboard.writeText(rows.map(r=>r['运单号']).filter(Boolean).join('\n')).then(()=>{state.copyMessage=`已复制 ${rows.length} 个运单号`;render()}).catch(()=>{state.copyMessage='复制失败，请检查浏览器权限';render()})};render();
</script>'''
customer_modules_ui = r'''<style>
.customer-summary{display:flex;gap:10px;flex-wrap:wrap;margin:16px 0}.customer-summary div{min-width:132px;padding:13px 15px;background:#f8fbff;border:1px solid #dbe8ff;border-radius:12px}.customer-summary span{display:block;color:var(--muted);font-size:12px}.customer-summary strong{display:block;margin-top:5px;font-size:23px;color:var(--blue)}.customer-grid{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:13px}.customer-module{display:grid;gap:14px;padding:16px;border:1px solid var(--line);border-radius:14px;background:#fff;box-shadow:0 2px 6px #17203308;transition:.16s}.customer-module:hover{border-color:#bcd2ff;box-shadow:0 9px 22px #17203312;transform:translateY(-2px)}.customer-module-head{display:flex;justify-content:space-between;align-items:flex-start;gap:8px}.customer-module-code{font-size:17px;font-weight:800;letter-spacing:.2px}.customer-module-main{display:flex;align-items:baseline;gap:4px}.customer-module-main strong{font-size:27px;line-height:1}.customer-module-main span{color:var(--muted);font-size:12px}.customer-module-meta{display:grid;gap:8px}.customer-module-meta div{display:flex;justify-content:space-between;gap:10px;font-size:12px}.customer-module-meta span{color:var(--muted)}.customer-module-meta b{font-weight:650;text-align:right;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.customer-module-actions{display:flex;gap:8px;padding-top:2px}.customer-module-actions button{border:0;background:#edf3ff;color:var(--blue);padding:8px 10px;border-radius:8px;font-size:12px;font-weight:700}@media(max-width:1100px){.customer-grid{grid-template-columns:repeat(3,minmax(0,1fr))}}@media(max-width:760px){.customer-grid{grid-template-columns:repeat(2,minmax(0,1fr))}}@media(max-width:480px){.customer-grid{grid-template-columns:1fr}}
</style><script>
const validCustomerCode=x=>/^[tz]/i.test(String(x||'').trim());
customers=function(){const m=new Map();D.orders.filter(r=>validCustomerCode(r['客户编码'])).forEach(r=>{const id=String(r['客户编码']).trim().toLowerCase();if(!m.has(id))m.set(id,{id,name:id,orders:0,last:r['拣货日期'],status:'正常'});const x=m.get(id);x.orders++;if(String(r['拣货日期'])>String(x.last))x.last=r['拣货日期']});D.focus.forEach(r=>{const id=String(r['客户编码']||'').trim().toLowerCase();if(m.has(id)){let x=m.get(id);x.status=String(r['优先级']).startsWith('P0')?'风险客户':String(r['优先级']).startsWith('P1')?'重点关注':'正常'}});return [...m.values()].sort((a,b)=>b.orders-a.orders)};
customerPage=function(){let rows=customers().filter(x=>!state.q||JSON.stringify(x).toLowerCase().includes(state.q.toLowerCase())),risk=rows.filter(x=>x.status==='风险客户').length,focus=rows.filter(x=>x.status==='重点关注').length;return `<section class="card"><div class="section-head"><div><h2>我的客户</h2><p>仅显示方涛负责且客户编号以 t / z 开头的客户</p></div><div class="filters"><input placeholder="搜索客户编号" value="${esc(state.q)}" oninput="state.q=this.value;render()"></div></div><div class="customer-summary"><div><span>规范客户</span><strong>${rows.length}</strong></div><div><span>风险客户</span><strong style="color:var(--red)">${risk}</strong></div><div><span>重点关注</span><strong style="color:var(--yellow)">${focus}</strong></div></div><div class="customer-grid">${rows.map(x=>{let contact=state.records.find(r=>String(r.customer).trim().toLowerCase()===x.id);return `<article class="customer-module"><div class="customer-module-head"><div class="customer-module-code">${esc(x.id)}</div>${tag(x.status)}</div><div class="customer-module-main"><strong>${x.orders}</strong><span>近三月运单</span></div><div class="customer-module-meta"><div><span>最近下单</span><b>${esc(x.last)}</b></div><div><span>最近联系</span><b>${esc(contact?.time||'暂无记录')}</b></div></div><div class="customer-module-actions"><button onclick="state.q='${x.id}';state.tab='shipments';render()">查看运单</button><button onclick="state.q='${x.id}';state.tab='records';render()">记录跟进</button></div></article>`}).join('')}</div>${rows.length?'':'<div class="empty">没有符合条件的规范客户编号</div>'}</section>`};render();
</script>'''
homepage_drilldown_ui = r'''<style>
.metric.drill{cursor:pointer;position:relative;transition:transform .16s,box-shadow .16s}.metric.drill:hover{transform:translateY(-3px);box-shadow:0 10px 24px #17203318}.metric.drill::after{content:'查看明细 →';position:absolute;right:15px;bottom:13px;color:var(--blue);font-size:11px;font-weight:700;opacity:0;transform:translateY(3px);transition:.16s}.metric.drill:hover::after{opacity:1;transform:none}.metric.drill:hover small{opacity:0}.metric.drill:focus-visible{outline:3px solid #b9d0ff;outline-offset:2px}
</style><script>
state.alertRiskOnly ||= false;state.receivableRiskOnly ||= false;state.customerFocusOnly ||= false;
const baseCustomersForDrill=customers;customers=function(){return baseCustomersForDrill().filter(x=>!state.customerFocusOnly||x.status!=='正常')};
function openMetricDrill(kind){state.q='';if(kind==='tasks'){state.tab='today';render();setTimeout(()=>document.querySelector('#today-tasks')?.scrollIntoView({behavior:'smooth',block:'start'}),0);return}if(kind==='alerts'){state.tab='alerts';state.alertView='monitor';state.alertMode='全部';state.alertStage='全部';state.alertRiskOnly=true}if(kind==='unsigned'){state.tab='alerts';state.alertView='monitor';state.alertMode='全部';state.alertStage='全部';state.alertRiskOnly=false}if(kind==='quotes'){state.tab='quotes'}if(kind==='receivables'){state.tab='receivables';state.receivableRiskOnly=true}if(kind==='customers'){state.tab='customers';state.customerFocusOnly=true}render()}
today=function(){let tasks=taskList(),done=tasks.filter(t=>state.tasks[t.id]==='done').length,abnormal=D.alerts.filter(r=>r['预警阶段']==='问题件'||days(r)>7).length,due=D.receivables.filter(r=>r['收款状态']==='高风险').length,cards=[['今日待处理',tasks.length,'red','tasks'],['异常运单',abnormal,'red','alerts'],['待签收',D.alerts.length,'yellow','unsigned'],['待报价',state.quotes.filter(x=>x.status==='待报价').length,'yellow','quotes'],['待收款',due,'yellow','receivables'],['待跟进客户',D.focus.length,'blue','customers']];return `<div class="grid metrics">${cards.map(x=>`<button class="card metric ${x[2]} drill" onclick="openMetricDrill('${x[3]}')"><span>${x[0]}</span><b>${x[1]}</b><small>方涛负责范围</small></button>`).join('')}</div><div class="grid two" style="margin-top:16px"><section class="card" id="today-tasks"><div class="section-head"><div><h2>今日必须处理</h2><p>按异常、应收与客户风险优先级排序</p></div><span class="tag red">${tasks.length} 项待办</span></div><div class="task-list">${tasks.slice(0,10).map(t=>`<div class="task ${t.kind} ${state.tasks[t.id]==='done'?'done':''}"><i></i><div><strong>${esc(t.title)}</strong><small>${esc(t.desc)}</small></div><div class="actions"><button onclick="showTask('${t.id}')">详情</button><button onclick="setTask('${t.id}','processing')">处理中</button><button onclick="setTask('${t.id}','done')">完成</button></div></div>`).join('')}</div></section><aside class="card summary"><div><h2>今日完成情况</h2><p class="muted">完成事项会保存在此浏览器</p></div><div class="summary-item"><span>今日任务</span><b>${tasks.length}</b></div><div class="summary-item"><span>已完成</span><b>${done}</b></div><div><div style="display:flex;justify-content:space-between"><span>完成率</span><strong>${tasks.length?Math.round(done/tasks.length*100):0}%</strong></div><div class="bar"><i style="width:${tasks.length?done/tasks.length*100:0}%"></i></div></div><div class="note">点击上方指标卡可进入对应明细并自动筛选。</div></aside></div>`};
receivable=function(){let rows=D.receivables.filter(r=>(!state.receivableRiskOnly||r['收款状态']==='高风险')&&(!state.q||JSON.stringify(r).toLowerCase().includes(state.q.toLowerCase())));return `<section class="card"><div class="section-head"><div><h2>应收跟进</h2><p>${state.receivableRiskOnly?'当前仅显示高风险待收款客户':'仅提醒助理需要联系的方涛客户；数据来自当天应收报表'}</p></div><div class="filters"><input placeholder="搜索客户" value="${esc(state.q)}" oninput="state.q=this.value;render()">${state.receivableRiskOnly?'<button class="copy" onclick="state.receivableRiskOnly=false;render()">查看全部</button>':''}</div></div>${table([['用户','客户'],['结算方式','结算方式'],['未支付','待收款'],['收款状态','提醒级别'],['销售','销售']],rows.map(r=>({...r,未支付:money(r['未支付'])})))}</section>`};const baseRenderForDrill=render;render=function(){baseRenderForDrill();let nav=[...document.querySelectorAll('#nav button')];let customerNav=nav.find(x=>x.textContent==='我的客户');if(customerNav)customerNav.onclick=()=>{state.tab='customers';state.q='';state.customerFocusOnly=false;render()};let alertNav=nav.find(x=>x.textContent==='预警中心');if(alertNav)alertNav.onclick=()=>{state.tab='alerts';state.q='';state.alertRiskOnly=false;render()};let receivableNav=nav.find(x=>x.textContent==='应收跟进');if(receivableNav)receivableNav.onclick=()=>{state.tab='receivables';state.q='';state.receivableRiskOnly=false;render()}};render();
</script>'''
volume_ranking_ui = r'''<style>
.customer-summary>div.drill{cursor:pointer;transition:.16s}.customer-summary>div.drill:hover{transform:translateY(-2px);box-shadow:0 8px 18px #1d4ed81a;border-color:#9dbdff}.volume-page{display:grid;gap:16px}.volume-page-head{display:flex;justify-content:space-between;gap:14px;align-items:flex-start}.volume-page-head p{margin:5px 0 0;color:var(--muted)}.range-switch{display:flex;padding:4px;border-radius:10px;background:#e9eef6}.range-switch button{border:0;border-radius:8px;background:transparent;color:#64748b;padding:8px 12px;font-weight:700}.range-switch button.active{color:var(--blue);background:#fff;box-shadow:0 1px 5px #17203316}.volume-summary{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:15px}.volume-summary-card{padding:18px}.volume-summary-card h2{font-size:18px}.volume-summary-card>p{color:var(--muted);margin:5px 0 15px}.volume-kpis{display:grid;grid-template-columns:repeat(4,1fr);gap:8px}.volume-kpis div{padding:10px;border-radius:10px;background:#f8fafc}.volume-kpis span{display:block;color:var(--muted);font-size:11px}.volume-kpis strong{display:block;margin-top:5px;font-size:19px}.rank-grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:15px}.rank-card{padding:0;overflow:hidden}.rank-head{display:flex;align-items:center;justify-content:space-between;padding:17px 18px 11px}.rank-head p{margin:4px 0 0;color:var(--muted);font-size:12px}.rank-card .table{border:0;border-radius:0;max-height:570px}.rank-card th{background:#f7f9fc;padding:12px}.rank-card td{padding:11px}.rank-num{color:var(--muted);font-weight:700}.rank-action{border:0;background:#edf3ff;color:var(--blue);padding:6px 8px;border-radius:7px;font-size:11px;font-weight:700}.volume-note{padding:12px 14px;background:#eff6ff;border-radius:10px;color:#1d4ed8;font-size:12px}@media(max-width:1050px){.volume-summary,.rank-grid{grid-template-columns:1fr}}@media(max-width:620px){.volume-page-head{flex-direction:column}.volume-kpis{grid-template-columns:repeat(2,1fr)}}
</style><script>
state.volumePage ||= false;state.volumeRange ||= 7;state.customerSummaryFilter ||= 'all';
const baseCustomersForSummary=customers;customers=function(){return baseCustomersForSummary().filter(x=>state.customerSummaryFilter==='risk'?x.status==='风险客户':state.customerSummaryFilter==='focus'?x.status==='重点关注':true)};
const dateStamp=v=>Date.parse(String(v||'').slice(0,10)+'T00:00:00');
const transportOf=r=>String(r['服务']||'').includes('海运')?'sea':String(r['服务']||'').includes('空运')?'air':'';
function volumeByCustomer(mode,range){let end=dateStamp(D.date),start=end-(range-1)*86400000,map=new Map();D.orders.filter(r=>validCustomerCode(r['客户编码'])&&transportOf(r)===mode&&dateStamp(r['拣货日期'])>=start&&dateStamp(r['拣货日期'])<=end).forEach(r=>{let id=String(r['客户编码']).trim().toLowerCase(),x=map.get(id)||{id,tickets:0,pieces:0,weight:0,last:r['拣货日期']};x.tickets++;x.pieces+=Number(r['件数']||0);x.weight+=Number(r['收费重']||0);if(String(r['拣货日期'])>String(x.last))x.last=r['拣货日期'];map.set(id,x)});return [...map.values()].sort((a,b)=>b.weight-a.weight||b.tickets-a.tickets)}
function volumeStats(mode,range){let rows=volumeByCustomer(mode,range);return {tickets:rows.reduce((s,x)=>s+x.tickets,0),pieces:rows.reduce((s,x)=>s+x.pieces,0),weight:rows.reduce((s,x)=>s+x.weight,0),customers:rows.length}}
function volumePage(){let range=state.volumeRange,air=volumeStats('air',range),sea=volumeStats('sea',range),label=`近${range}天`,summary=(title,s,tone)=>`<section class="card volume-summary-card"><h2>${title}走货货量</h2><p>${label} · 按拣货时间汇总</p><div class="volume-kpis"><div><span>票数</span><strong>${num(s.tickets)} 票</strong></div><div><span>件数</span><strong>${num(s.pieces)} 件</strong></div><div><span>计费重</span><strong>${num(s.weight)} kg</strong></div><div><span>客户数</span><strong style="color:var(--${tone})">${num(s.customers)} 家</strong></div></div></section>`,ranking=(mode,title)=>{let rows=volumeByCustomer(mode,range);return `<section class="card rank-card"><div class="rank-head"><div><h2>${title}客户走货排行榜</h2><p>${label} · 按计费重排序</p></div><span class="tag ${mode==='sea'?'green':'blue'}">Top ${Math.min(rows.length,15)}</span></div><div class="table"><table><thead><tr><th>#</th><th>客户编号</th><th>${label}票数</th><th>${label}件数</th><th>${label}计费重</th><th>最近拣货</th><th></th></tr></thead><tbody>${rows.slice(0,15).map((r,i)=>`<tr><td class="rank-num">${i+1}</td><td><strong>${esc(r.id)}</strong></td><td>${num(r.tickets)}票</td><td>${num(r.pieces)}件</td><td><strong>${num(r.weight)} kg</strong></td><td>${esc(r.last)}</td><td><button class="rank-action" onclick="state.volumePage=false;state.q='${r.id}';state.tab='shipments';render()">查看运单</button></td></tr>`).join('')}</tbody></table></div></section>`};return `<main class="volume-page"><div class="volume-page-head"><div><h2>空运 / 海运客户走货</h2><p>仅统计方涛负责、客户编号以 t/z 开头的有效运单</p></div><div class="range-switch"><button class="${range===7?'active':''}" onclick="state.volumeRange=7;render()">近7天</button><button class="${range===30?'active':''}" onclick="state.volumeRange=30;render()">近30天</button></div></div><div class="volume-summary">${summary('空运',air,'blue')}${summary('海运',sea,'green')}</div><div class="rank-grid">${ranking('air','空运')}${ranking('sea','海运')}</div><div class="volume-note">口径说明：票数、件数与计费重均按拣货时间汇总。当前三张源报表不含逐票营业额，因此本页不展示或估算营业额。</div></main>`}
const renderBeforeVolume=render;render=function(){renderBeforeVolume();let nav=$('#nav');[...nav.querySelectorAll('button')].forEach(b=>{let original=b.onclick;b.onclick=e=>{state.volumePage=false;original?.call(b,e)}});let volumeNav=document.createElement('button');volumeNav.textContent='走货排行';volumeNav.className=state.volumePage?'active':'';volumeNav.onclick=()=>{state.volumePage=true;state.tab='today';render()};nav.append(volumeNav);if(state.volumePage){$('#app').innerHTML=volumePage();volumeNav.classList.add('active')}if(state.tab==='customers'&&!state.volumePage){let cards=[...document.querySelectorAll('.customer-summary>div')];let filters=['all','risk','focus'];cards.forEach((card,i)=>{card.classList.add('drill');card.tabIndex=0;card.onclick=()=>{state.customerSummaryFilter=filters[i];state.q='';render()};card.onkeydown=e=>{if(e.key==='Enter')card.click()}})}};render();
</script>'''
channel_summary_ui = r'''<style>
.channel-grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:15px}.channel-card{padding:0;overflow:hidden}.channel-head{padding:17px 18px 11px}.channel-head h2{font-size:18px}.channel-head p{margin:4px 0 0;color:var(--muted);font-size:12px}.channel-card .table{border:0;border-radius:0;max-height:430px}.channel-card th{padding:12px;background:#f7f9fc}.channel-card td{padding:11px}.trend-up{color:var(--green);font-weight:700}.trend-down{color:var(--red);font-weight:700}.trend-flat{color:var(--muted);font-weight:700}@media(max-width:1050px){.channel-grid{grid-template-columns:1fr}}
</style><script>
function volumeOrders(mode,range,offset=0){let end=dateStamp(D.date)-offset*range*86400000,start=end-(range-1)*86400000;return D.orders.filter(r=>validCustomerCode(r['客户编码'])&&transportOf(r)===mode&&dateStamp(r['拣货日期'])>=start&&dateStamp(r['拣货日期'])<=end)}
function channelSummary(mode,range){let current=new Map(),previous=new Map();for(const [map,rows] of [[current,volumeOrders(mode,range)],[previous,volumeOrders(mode,range,1)]])rows.forEach(r=>{let service=r['服务']||'未分类服务',x=map.get(service)||{service,tickets:0,pieces:0,weight:0,customers:new Set()};x.tickets++;x.pieces+=Number(r['件数']||0);x.weight+=Number(r['收费重']||0);x.customers.add(String(r['客户编码']).trim().toLowerCase());map.set(service,x)});return [...current.values()].map(x=>{let old=previous.get(x.service)?.tickets||0;let trend=old?((x.tickets-old)/old*100):x.tickets?100:0;return {...x,customerCount:x.customers.size,trend}}).sort((a,b)=>b.weight-a.weight||b.tickets-a.tickets)}
function channelTable(mode,title){let rows=channelSummary(mode,state.volumeRange),label=`近${state.volumeRange}天`;let trend=x=>x.trend===100?'新渠道':`${x.trend>0?'+':''}${x.trend.toFixed(1)}%`;return `<section class="card channel-card"><div class="channel-head"><h2>${title}渠道货量</h2><p>${rows.length} 个${title}服务 · ${label}按拣货时间汇总</p></div><div class="table"><table><thead><tr><th>渠道 / 服务</th><th>${label}票数</th><th>${label}件数</th><th>${label}计费重</th><th>${label}客户</th><th>近期趋势</th><th></th></tr></thead><tbody>${rows.map(r=>`<tr><td><strong>${esc(r.service)}</strong></td><td>${num(r.tickets)}票</td><td>${num(r.pieces)}件</td><td><strong>${num(r.weight)} kg</strong></td><td>${num(r.customerCount)}家</td><td><span class="${r.trend>0?'trend-up':r.trend<0?'trend-down':'trend-flat'}">${trend(r)}</span></td><td><button class="rank-action" onclick="state.volumePage=false;state.q='${esc(r.service)}';state.tab='shipments';render()">查看运单</button></td></tr>`).join('')}</tbody></table></div></section>`}
const baseVolumePageWithChannels=volumePage;volumePage=function(){let base=baseVolumePageWithChannels();let channels=`<div class="channel-grid">${channelTable('air','空运')}${channelTable('sea','海运')}</div>`;return base.replace('<div class="rank-grid">',channels+'<div class="rank-grid">')};render();
</script>'''
html = html.replace('</body></html>', enhanced_alert_ui + customer_modules_ui + homepage_drilldown_ui + volume_ranking_ui + channel_summary_ui + '</body></html>')

target = Path(__file__).resolve().parent / 'site/index.html'
target.write_text(html)
target.parent.parent.joinpath('index.html').write_text(html)
print(f'Wrote {target} with {len(orders)} 方涛运单、{len(alerts)} 条预警、{len(receivables)} 条应收。')
